#import "VoiceEffectCell.h"


@interface VoiceEffectCell ()

@end

@implementation VoiceEffectCell

- (instancetype)initWithFrame:(CGRect)frame {
    self = [super initWithFrame:frame];
    if (self) {
        [self setUpUI];
    }
    return self;
}

- (void)setUpUI {
    self.backgroundColor = WHITE_COLOR;


    [self addSubview:self.infoView];
    [self.infoView addSubview:self.nameLabel];
    [self.infoView addSubview:self.decribeLabel];
    [self.infoView addSubview:self.playButton];

    [self addSubview:self.icon];
    [self addSubview:self.selectedButton];

    [self.icon mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.right.top.equalTo(self).inset(ZOOM(6));
        make.bottom.equalTo(self.infoView.mas_top).offset(ZOOM(-6));
    }];

    [self.selectedButton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.right.top.equalTo(self);
        make.size.mas_equalTo(ZOOM(32));
    }];

    [self.infoView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.height.mas_equalTo(ZOOM(60));
        make.left.equalTo(self).offset(ZOOM(6));
        make.right.bottom.equalTo(self).offset(ZOOM(-6));
    }];

    [self.nameLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.infoView).offset(ZOOM(8));
        make.left.equalTo(self.infoView).offset(ZOOM(6));
    }];

    [self.decribeLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.bottom.equalTo(self.infoView).offset(ZOOM(-8));
        make.left.equalTo(self.infoView).offset(ZOOM(6));
    }];

    [self.playButton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.right.bottom.equalTo(self).offset(ZOOM(-6));
        make.size.mas_equalTo(ZOOM(24));
    }];
}

#pragma mark - Lazy

- (UIImageView *)icon {
    if (_icon == nil) {
        _icon = [[UIImageView alloc] init];
    }
    return _icon;
}

- (UIView *)infoView {
    if (!_infoView) {
        _infoView = [[UIView alloc] init];
        _infoView.backgroundColor = RGBA(237, 237, 237, 1);
        _infoView.layer.cornerRadius = ZOOM(16);
    }
    return _infoView;
}

- (UILabel *)nameLabel {
    if (_nameLabel == nil) {
        _nameLabel = [[UILabel alloc] init];
        _nameLabel.font = [UIFont systemFontOfSize:16.0];
    }
    return _nameLabel;
}

- (UILabel *)decribeLabel {
    if (_decribeLabel == nil) {
        _decribeLabel = [[UILabel alloc] init];
        _decribeLabel.font = [UIFont systemFontOfSize:14.0];
        _decribeLabel.textColor = RGBA(153, 153, 153, 1);
    }
    return _decribeLabel;
}

- (UIButton *)selectedButton {
    if (_selectedButton == nil) {
        _selectedButton = [[UIButton alloc] init];
        [_selectedButton setBackgroundImage:[UIImage imageNamed:@"A_noSelected"] forState:UIControlStateNormal];
        [_selectedButton setBackgroundImage:[UIImage imageNamed:@"A_isSelected"] forState:UIControlStateSelected];
        _selectedButton.userInteractionEnabled = NO;
    }
    return _selectedButton;
}

- (UIButton *)playButton {
    if (_playButton == nil) {
        _playButton = [[UIButton alloc] init];
        [_playButton setBackgroundImage:[UIImage imageNamed:@"A_Unable"] forState:UIControlStateDisabled];
        [_playButton setBackgroundImage:[UIImage imageNamed:@"A_play"] forState:UIControlStateNormal];
        [_playButton setBackgroundImage:[UIImage imageNamed:@"A_pause"] forState:UIControlStateSelected];
        _playButton.hitTestEdgeInsets = UIEdgeInsetsMake(-20, -20, -20, -20);
//        _playButton.userInteractionEnabled = NO;
    }
    return _playButton;
}


@end

