#import "VoiceChangeViewController.h"
#import "PrefixHeader.h"
#import "ToneView.h"
@import AVFoundation;

#if ENABLE_ADS

#import <BUAdSDK/BUAdSDK.h>
#import "AdManager.h"

@interface VoiceChangeViewController () <WKNavigationDelegate, BUNativeExpressBannerViewDelegate>

@property(strong, nonatomic) BUNativeExpressBannerView *bannerAdView;
@property(assign, nonatomic) CGFloat bannerAdHeight;

#else

@interface VoiceChangeViewController ()

#endif

@property (nonatomic, strong) NSArray<ToneView *> *tones;
@property (nonatomic, strong) UIView *ToneView;
@property (nonatomic, strong) UIButton *recordButton;
@property (nonatomic, strong) UIButton *playButton;

@property (nonatomic, strong) ToneView *selectedView;
@property (nonatomic, assign) BOOL hasRecord;

@property (nonatomic, copy) NSString *selectedEffect;
@property (nonatomic, strong) NSArray *effectData;

@property (nonatomic, strong) AVAudioRecorder *recorder;
@property (nonatomic, strong) NSURL *recordFileURL;
@property (nonatomic, strong) AVAudioEngine *engine;
@property (nonatomic, strong) AVAudioPlayerNode *playerNode;
@property (nonatomic, strong) AVAudioUnitTimePitch *pitchNode;

@property (nonatomic, assign) BOOL isPlaying;
@property (nonatomic, strong) AVAudioFile *audioFile;

@property (nonatomic, strong) UILabel *tipLabel;

@end

@implementation VoiceChangeViewController

#pragma mark - Lifecycle

- (instancetype)init {
    self = [super init];
    if (self) {
        self.selectedEffect = @"chipmunk";
#if ENABLE_ADS

        self.bannerAdHeight = ZOOM(75);

#endif
    }
    return self;
}

- (void)viewDidLoad {
    [super viewDidLoad];
    self.view.backgroundColor = UIColor.whiteColor;
    [self setupData];
    [self setupUI];
    [self setupAudioSession];
}
#if ENABLE_ADS

- (void)viewWillAppear:(BOOL)animated {
    [super viewWillAppear:animated];
    [self groMoreBannerAdLoad]; // 加载banner广告
}

#endif

- (void)setupGradientBackground {
    // 创建渐变层
    CAGradientLayer *gradientLayer = [CAGradientLayer layer];
    gradientLayer.frame = self.view.bounds;

    // 设置渐变颜色 - 从上到下
    UIColor *topColor = [UIColor colorWithRed:187/255.0 green:231/255.0 blue:250/255.0 alpha:1.0];
    UIColor *bottomColor = [UIColor colorWithRed:240/255.0 green:251/255.0 blue:255/255.0 alpha:1.0];

    gradientLayer.colors = @[
        (id)topColor.CGColor,
        (id)bottomColor.CGColor
    ];

    // 设置渐变方向 - 从上到下
    gradientLayer.startPoint = CGPointMake(0.5, 0.0); // 顶部中间
    gradientLayer.endPoint = CGPointMake(0.5, 1.0);   // 底部中间

    // 添加到视图最底层
    [self.view.layer insertSublayer:gradientLayer atIndex:0];

}

- (void)setupData {
    self.effectData = @[
        @{
            @"title": @"Cartoon voice",
            @"description": @"Children",
            @"type": @"chipmunk",
            @"image": @"A_cartoon"
        },
        @{
            @"title": @"Robot voice",
            @"description": @"Robot",
            @"type": @"robot",
            @"image": @"A_robot"
        },
        @{
            @"title": @"Female voice",
            @"description": @"Girl",
            @"type": @"girl",
            @"image": @"A_female"
        },
        @{
            @"title": @"Male voice",
            @"description": @"Boy",
            @"type": @"deep",
            @"image": @"A_uncle"
        },

    ];
}

- (void)toneSelected:(ToneView *)selectedTone {
    self.selectedEffect = selectedTone.type;
    [self updateToneSelectionUI];
    [self stopPlayback];
    if (self.recordFileURL) {
        [self playWithEffect:self.selectedEffect];
    }
}

#pragma mark - Setup UI

- (void)setupUI {
    [self setupToneView];
    [self setupControlButtons];
    [self updateToneSelectionUI];
    [self updatePlaybackControlState];
}

- (void)setupToneView {
    CGFloat itemHeight = ZOOMW(112);
    CGFloat itemGap = ZOOMW(10);
    NSInteger numberOfRows = (self.effectData.count + 1) / 2;
    CGFloat totalHeight = numberOfRows * itemHeight + MAX(numberOfRows - 1, 0) * itemGap;

    self.ToneView = [[UIView alloc] init];
    [self.view addSubview:self.ToneView];
