#import "AudioManager.h"

@implementation AudioManager {
    AVPlayer *_backgroundPlayer;
    AVAudioPlayer *_successPlayer;
    AVAudioPlayer *_deletePlayer;
}

+ (instancetype)sharedInstance {
    static AudioManager *instance = nil;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        instance = [[self alloc] init];
    });
    return instance;
}

- (instancetype)init {
    self = [super init];
    if (self) {
        // 初始化音频会话（支持后台 + 混音）
        NSError *error;
        [[AVAudioSession sharedInstance] setCategory:AVAudioSessionCategoryPlayback
                                         withOptions:AVAudioSessionCategoryOptionMixWithOthers
                                               error:&error];
        if (error) NSLog(@"Audio session error: %@", error);
        [[AVAudioSession sharedInstance] setActive:YES error:&error];

        // 背景音乐
        NSURL *bgURL = [[NSBundle mainBundle] URLForResource:@"A_Snow_sound" withExtension:@"mp3"];
        AVPlayerItem *item = [AVPlayerItem playerItemWithURL:bgURL];
        _backgroundPlayer = [AVPlayer playerWithPlayerItem:item];
//        [_backgroundPlayer addObserver:self forKeyPath:@"status" options:0 context:nil];

        [[NSNotificationCenter defaultCenter] addObserver:self
                                                         selector:@selector(backgroundMusicDidFinish:)
                                                             name:AVPlayerItemDidPlayToEndTimeNotification
                                                           object:item];

        // 成功音效
        NSURL *successURL = [[NSBundle mainBundle] URLForResource:@"A_Success_sound" withExtension:@"mp3"];
        _successPlayer = [[AVAudioPlayer alloc] initWithContentsOfURL:successURL error:nil];
        _successPlayer.delegate = nil; // 不需要循环

        // 删除音效
        NSURL *deleteURL = [[NSBundle mainBundle] URLForResource:@"A_Delete_sound" withExtension:@"mp3"];
        _deletePlayer = [[AVAudioPlayer alloc] initWithContentsOfURL:deleteURL error:nil];

        // 默认开启音效（可从 UserDefaults 读取）
        _successSoundEnabled = YES;
        _deleteSoundEnabled = YES;
        _backgroundMusicEnabled = NO;
    }
    return self;
}

- (void)dealloc {
    [[NSNotificationCenter defaultCenter] removeObserver:self
                                                        name:AVPlayerItemDidPlayToEndTimeNotification
                                                      object:nil];
}

#pragma mark - Background Music

- (void)setBackgroundMusicEnabled:(BOOL)enabled {
    _backgroundMusicEnabled = enabled;
    if (enabled) {
        [_backgroundPlayer play];
    } else {
        [_backgroundPlayer pause];
    }
}

- (void)toggleBackgroundMusic {
    if (_backgroundPlayer.rate == 0) {
        [_backgroundPlayer play];
    } else {
        [_backgroundPlayer pause];
    }
}

- (void)backgroundMusicDidFinish:(NSNotification *)notification {
    if (!_backgroundMusicEnabled) return;

    __weak __typeof(self)weakSelf = self;
    // 重置播放位置到开头，并继续播放
    [_backgroundPlayer seekToTime:kCMTimeZero completionHandler:^(BOOL finished) {
        if (finished && weakSelf.backgroundMusicEnabled) {
            [_backgroundPlayer play];
        }
    }];
}

#pragma mark - Sound Effects (with switch control)

- (void)playSuccessSoundIfAllowed {
    if (self.successSoundEnabled && _successPlayer) {
        [_successPlayer stop]; // 防止重叠（可选）
        [_successPlayer prepareToPlay];
        [_successPlayer play];
    }
}

- (void)playDeleteSoundIfAllowed {
    if (self.deleteSoundEnabled && _deletePlayer) {
        [_deletePlayer stop];
        [_deletePlayer prepareToPlay];
        [_deletePlayer play];
    }
}


@end

