- (void)setIsCalling:(BOOL)isCalling {
    _isCalling = isCalling;
    if (isCalling == YES) {
        self.stratButton.hidden = YES;
        self.teleButton.hidden = NO;
        self.hungupButton.hidden = NO;
        self.tipLabel.hidden = NO;
        self.isPause = NO;
    } else {
        self.stratButton.hidden = NO;
        self.teleButton.hidden = YES;
        self.hungupButton.hidden = YES;
        self.tipLabel.hidden = YES;
        self.isPause = YES;
        [self stopSpeech];
        [self stopAction];
    }
}

- (void)setIsPause:(BOOL)isPause {
    _isPause = isPause;
    if (isPause == YES) {
        [self.teleButton setBackgroundImage:[UIImage imageNamed:@"A_Pause"] forState:UIControlStateNormal];
        self.tipLabel.text = @"Tap to continue chatting";
        [self stopAction];
        [self pauseSpeech];
    } else {
        [self.teleButton setBackgroundImage:[UIImage imageNamed:@"A_Start"] forState:UIControlStateNormal];
        self.tipLabel.text = @"Speak now, I'm listening";
        [self resumeSpeech];
        [self startAction];
    }
}

