- (void)startAction {
    [[SpeechManager shared] startRecognize:^(NSString *text) {
        self.textLabel.text = text;
        [[SpeechManager shared] stopRecognize];
        NSLog(@"self.textLabel.text: %@", text);
        [self onSendMessageButtonTappedWithId:AIID];
    }];

}

- (void)stopAction {
    [[SpeechManager shared] stopRecognize];
}

- (void)onSendMessageButtonTappedWithId:(NSNumber *)ID {

    // 获取输入框中的消息内容
    NSString *messageText ;

    // 获取输入框中的消息内容
    messageText = self.textLabel.text;

    // 检测是否为空消息，纯空格或者纯换行符
    NSString *trimmedString = [messageText stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
    if ([messageText isEqualToString:@""]||[trimmedString length] == 0) {
        // 如果消息为空，则不处理
        return;
    }

    NSString *currentContextString = [self contextJSONStringFromArray:[self latestValidContextArray]];
    // 创建新的发送消息对象，这里context从上一条MessageTypeReceived属性的MessageModel中或许
    [self.messages addObject:[[MessageModel alloc] initWithText:messageText time:[NSDate date] type:MessageTypeSent accountId:AIID cellHeight:0 context:currentContextString Done:NO]];
    // 清空输入框

    [MessageModel saveMessagesForAccount:AIID];    // 保存消息
    [MessageModel saveMessageNum:[MessageModel messagenum]];

    [self sendPOSTRequestAndHandleStreamResponse:messageText];  // 发送消息，
}

- (void)addTarget {
    [self.stratButton addTarget:self action:@selector(changeCalling:) forControlEvents:UIControlEventTouchUpInside];
    [self.hungupButton addTarget:self action:@selector(changeCalling:) forControlEvents:UIControlEventTouchUpInside];
    [self.teleButton addTarget:self action:@selector(changeStatus:) forControlEvents:UIControlEventTouchUpInside];
}

- (void)changeCalling:(UIButton *)sender {
    self.isCalling = !_isCalling;
}

- (void)changeStatus:(UIButton *)sender {
    self.isPause = !_isPause;
}

#pragma mark - 网络请求
/*
 使用NSURLSessionDataDelegate和didReceiveData而非completionHandler
 底层差异：
 数据流和缓冲机制的差异：
 NSURLSessionDataDelegate：基于 数据流，数据分批传输到应用层，系统只负责接收，处理逻辑由开发者决定。每个数据块到达时，didReceiveData: 方法被调用，允许你立即处理数据。
 completionHandler：基于 缓冲机制，系统负责将所有数据接收完毕并缓存在本地，只有当全部数据接收完毕后才调用 completionHandler，并将数据一次性提供给应用层。
触发时机的差异：
NSURLSessionDataDelegate：代理方法根据网络传输状态多次触发。每当数据从网络到达时，系统会调用代理方法，开发者可以在这些调用中实时处理数据。
completionHandler：只有在数据完全接收后，才会一次性触发。你无法在数据传输过程中干预或处理部分数据。
 */
- (NSArray *)contextArrayFromJSONString:(NSString *)contextString {
    if (![contextString isKindOfClass:[NSString class]]) {
        return nil;
    }
    NSString *trimmedContext = [contextString stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
    if (trimmedContext.length == 0) {
        return nil;
    }
    NSData *jsonData = [trimmedContext dataUsingEncoding:NSUTF8StringEncoding];
    if (!jsonData) {
        return nil;
    }
    NSError *error = nil;
    id contextObject = [NSJSONSerialization JSONObjectWithData:jsonData options:0 error:&error];
    if (error || ![contextObject isKindOfClass:[NSArray class]]) {
        return nil;
    }
    return contextObject;
}

- (NSArray *)normalizedContextArrayFromValue:(id)value fallback:(NSArray *)fallback {
    if ([value isKindOfClass:[NSArray class]]) {
        return value;
    }
    if ([value isKindOfClass:[NSString class]]) {
        NSArray *contextArray = [self contextArrayFromJSONString:value];
        if (contextArray) {
            return contextArray;
        }
    }
    return fallback ?: @[];
}

- (NSArray *)latestValidContextArray {
    for (NSInteger idx = self.messages.count - 1; idx >= 0; idx--) {
        NSArray *contextArray = [self contextArrayFromJSONString:self.messages[idx].context];
        if (contextArray && ![self isContextSentinelValue:contextArray]) {
            return contextArray;
        }
    }
    return @[];
}

- (NSString *)contextJSONStringFromArray:(NSArray *)contextArray {
    NSArray *safeContext = [contextArray isKindOfClass:[NSArray class]] ? contextArray : @[];
    NSError *error = nil;
    NSData *jsonData = [NSJSONSerialization dataWithJSONObject:safeContext options:0 error:&error];
    if (error || !jsonData) {
        NSLog(@"[Context] Serialize failed: %@", error.localizedDescription);
        return @"[]";
    }
    return [[NSString alloc] initWithData:jsonData encoding:NSUTF8StringEncoding] ?: @"[]";
}

- (BOOL)isContextSentinelValue:(NSArray *)contextArray {
    if (![contextArray isKindOfClass:[NSArray class]] || contextArray.count != 1) {
        return NO;
    }
    id firstObject = contextArray.firstObject;
    return [firstObject respondsToSelector:@selector(integerValue)] && [firstObject integerValue] == 1;
}

// 发送POST请求并处理流响应
- (void)sendPOSTRequestAndHandleStreamResponse:(NSString *)messageText {
    // 配置 URL 和请求
    //NSURL *url = [NSURL URLWithString:@"http://192.168.199.34:8100/ai"];
    NSURL *url = [NSURL URLWithString:AiServerManager.sharedManager.aiServerURL];
    NSMutableURLRequest *request = [NSMutableURLRequest requestWithURL:url];
    request.HTTPMethod = @"POST";
    [request setValue:@"application/json" forHTTPHeaderField:@"Content-Type"];
    // 每次开始新对话时要初始化如下内容
    _nowString = nil;
    // 注意：这里accumulatedResponse和buffer和是一个可变字符串，不要赋空，而要赋为空串
    [self.buffer setString:@""];
    [self.accumulatedResponse setString:@""];
    self.context = [self latestValidContextArray];
    NSLog(@"[Context] Sending: %@", self.context);
    NSMutableDictionary *params = [@{@"model": @"gemma2:2b",
                                     @"prompt": messageText,
                                     @"context": self.context ?: @[]} mutableCopy];
    if (self.Identity.length > 0) {
        params[@"system"] = self.Identity;
    }
    NSError *postError = nil;
    NSData *postData = [NSJSONSerialization dataWithJSONObject:params options:0 error:&postError];
    if (postError) {
        NSLog(@"[Context] Request body build failed: %@", postError.localizedDescription);
        return;
    }
    request.HTTPBody = postData;
    // 创建一个会话配置
    NSURLSessionConfiguration *sessionConfig = [NSURLSessionConfiguration defaultSessionConfiguration];
    // 创建 NSURLSession，并设置 delegate 和 delegateQueue
    NSURLSession *session = [NSURLSession sessionWithConfiguration:sessionConfig delegate:self delegateQueue:nil];
    self.dataTask = [session dataTaskWithRequest:request];
    [self.dataTask resume];
}


// 实现 NSURLSessionDataDelegate
// 注意：context数组的长度与ai返回的内容的长度成正比，如果ai返回一篇长文本会导致最后一条消息中的context太长，消息被切断，需要进行拼接
// 注意：会出现几条消息粘连在一起的情况，用换行符进行切割
// 注意：暂不确定以上两种情况会不会同时出现
- (void)URLSession:(NSURLSession *)session dataTask:(NSURLSessionDataTask *)dataTask didReceiveData:(NSData *)data {
    // 将接收到的数据转换为字符串，以便于处理
    NSString *dataString = [[NSString alloc] initWithData:data encoding:NSUTF8StringEncoding];
    NSError *error = nil;
    NSString *jsonPart;
    //进行切割工作
    NSRegularExpression *regex = [NSRegularExpression regularExpressionWithPattern:@"\\n\\n|\\n" options:0 error:&error];
    NSString *modifiedString = [regex stringByReplacingMatchesInString:dataString options:0 range:NSMakeRange(0, dataString.length) withTemplate:@"|"];
    NSArray *jsonStrings = [modifiedString componentsSeparatedByString:@"|"];
    for (NSString *DataString in jsonStrings) {
        //NSLog(@"DataString: %@", DataString);
        // 处理每个 JSON 字符串
        if ([DataString hasPrefix:@"data:"]) {
            jsonPart = [DataString substringFromIndex:5];
            if(![jsonPart isEqualToString:@""]){
                [self processJSONMessage:jsonPart];
            }
        }else{
            if(![DataString isEqualToString:@""]){
                [self processJSONMessage:DataString];
            }
        }
    }
}

//进行拼接工作
static const unichar closingBrace = '}';
- (void)processJSONMessage:(NSString *)jsonString {
    // 将字符串转换为 NSData 以进行 JSON 解析
    NSData *jsonData = [jsonString dataUsingEncoding:NSUTF8StringEncoding];
    NSError *jsonError;
    NSDictionary *responseDict = [NSJSONSerialization JSONObjectWithData:jsonData options:0 error:&jsonError];
    if (jsonError) {
        NSLog(@"Failed to parse JSON from server response: %@", jsonError);
        //不确定是否是因为消息被切断而导致的json解析出错，所以需要进行拼接
        [self.buffer appendString:jsonString];
        // 检测最后一个字符，如果是'}'，则代表是消息被切断导致的，json解析最后一条消息
        if([self.buffer characterAtIndex:self.buffer.length - 1]==closingBrace){
            NSLog(@"已拼接最后一条消息");
            // 注意：复用jsonError时要赋空
            jsonError = nil;
            jsonData = [self.buffer dataUsingEncoding:NSUTF8StringEncoding];
            responseDict = [NSJSONSerialization JSONObjectWithData:jsonData options:0 error:&jsonError];
            if(jsonError){
                NSLog(@"Failed to parse JSON from server response: %@", jsonError);
                NSLog(@"接收到的服务器消息: %@", self.buffer);
                return;
            }
            BOOL done = [responseDict[@"done"] boolValue];
            if(done){
                [self processDoneMessage:responseDict];
            }
        }
        return; // 跳过解析失败的消息
    }
    _preString = _nowString;
    _nowString = responseDict[@"response"];
    BOOL done = [responseDict[@"done"] boolValue];
    if (done) {
        [self processDoneMessage:responseDict];
        return;
    }
    if (_preString) {
        _preString = [self removeEmojisFromString:_preString];
        _preString = [_preString stringByReplacingOccurrencesOfString:@"*" withString:@""];
        _preString = [_preString stringByReplacingOccurrencesOfString:@"\n\n+" withString:@"\n" options:NSRegularExpressionSearch range:NSMakeRange(0, _preString.length)];
        [self.accumulatedResponse appendString:_preString];
        // 更新最后一条消息
        MessageModel *lastMessage = [self.messages lastObject];
        lastMessage.text = self.accumulatedResponse;
//        lastMessage.cellHeight = [self getStringWidthToCellHeight:self.accumulatedResponse];

        if ([_preString isEqual:@"!"] ||
            [_preString isEqual:@"?"] ||
            [_preString isEqual:@"."] ) {
            [_speackString appendString:_preString];
            [self addSentenceToSpeechQueue:_speackString];
            [_speackString setString:@""];
        } else {
            [_speackString appendString:_preString];
        }

    }
}

- (void)processDoneMessage:(NSDictionary *)Dict{
    dispatch_async(dispatch_get_main_queue(), ^{
        // 提取 context
        NSArray *lastContext = [self normalizedContextArrayFromValue:self.context fallback:@[]];
        NSArray *responseContext = [self normalizedContextArrayFromValue:Dict[@"context"] fallback:lastContext];
        NSLog(@"[Context] Response: %@", responseContext);
        NSArray *contextToSave = [self isContextSentinelValue:responseContext] ? lastContext : responseContext;
        self.context = contextToSave;
        self.messages.lastObject.context = [self contextJSONStringFromArray:contextToSave];
        self.messages.lastObject.done = YES;
        self.messages[self.messages.count - 1].done = YES;
        self.messages[self.messages.count - 2].context = @"";
        [MessageModel saveMessagesForAccount:AIID]; // 保存消息
        [MessageModel saveMessageNum:[MessageModel messagenum]];
        NSLog(@"[Context] Saved: %@", self.messages.lastObject.context);
    });
    NSLog(@"响应结束");

    [[SpeechManager shared] startRecognize:^(NSString *text) {
        self.textLabel.text = text;
        [[SpeechManager shared] stopRecognize];
        NSLog(@"self.textLabel.text: %@", text);
        [self onSendMessageButtonTappedWithId:AIID];
    }];
    return;
}

// 添加句子到语音队列的方法
- (void)addSentenceToSpeechQueue:(NSString *)sentence {
    if (!sentence || sentence.length == 0) return;

    // 清理句子中的特殊字符和多余空格
    NSString *cleanSentence = [self cleanSentenceForSpeech:sentence];
    if (cleanSentence.length > 0) {
        [[SpeechManager shared] addSpeechText:cleanSentence];
    }
}

// 清理句子，使其更适合语音合成
- (NSString *)cleanSentenceForSpeech:(NSString *)sentence {
    // 移除多余的空格和换行
    NSString *clean = [sentence stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];

    // 将多个连续空格替换为单个空格
    clean = [clean stringByReplacingOccurrencesOfString:@"\\s+" withString:@" " options:NSRegularExpressionSearch range:NSMakeRange(0, clean.length)];

    // 移除可能影响语音合成的特殊字符
    NSCharacterSet *specialChars = [NSCharacterSet characterSetWithCharactersInString:@"*#@$%^&<>"];
    clean = [[clean componentsSeparatedByCharactersInSet:specialChars] componentsJoinedByString:@""];

    return clean;
}

- (void)pauseSpeech {
    [[SpeechManager shared].synthesizer pauseSpeakingAtBoundary:AVSpeechBoundaryWord];
}

- (void)resumeSpeech {
    [[SpeechManager shared].synthesizer continueSpeaking];
}

- (void)stopSpeech {
    [[SpeechManager shared] clearQueue];
}

- (void)skipCurrentSpeech {
    SpeechManager *manager = [SpeechManager shared];
    [manager.synthesizer stopSpeakingAtBoundary:AVSpeechBoundaryImmediate];
}

- (NSString *)removeEmojisFromString:(NSString *)string {
    if (string.length == 0) {
        return string;
    }

    // 使用正则表达式过滤Emoji表情
    NSString *emojiPattern = @"[\\u2600-\\u26FF\\u2700-\\u27BF\\U0001F000-\\U0001F9FF]";
    NSError *error = nil;
    NSRegularExpression *regex = [NSRegularExpression regularExpressionWithPattern:emojiPattern
                                                                           options:NSRegularExpressionCaseInsensitive
                                                                             error:&error];
    if (error) {
        NSLog(@"正则表达式错误: %@", error);
        return string;
    }

    NSString *result = [regex stringByReplacingMatchesInString:string
                                                        options:0
                                                          range:NSMakeRange(0, string.length)
                                                   withTemplate:@""];

    return result;
}


