import Foundation
import ImageIO
import CoreGraphics

func analyze(_ path: String) {
    let url = URL(fileURLWithPath: path)
    guard let src = CGImageSourceCreateWithURL(url as CFURL, nil),
          let img = CGImageSourceCreateImageAtIndex(src, 0, nil) else {
        print(path, "LOAD_FAIL")
        return
    }
    let width = img.width
    let height = img.height
    let bytesPerPixel = 4
    let bytesPerRow = bytesPerPixel * width
    let bitsPerComponent = 8
    var data = [UInt8](repeating: 0, count: Int(height * bytesPerRow))
    guard let ctx = CGContext(data: &data,
                              width: width,
                              height: height,
                              bitsPerComponent: bitsPerComponent,
                              bytesPerRow: bytesPerRow,
                              space: CGColorSpaceCreateDeviceRGB(),
                              bitmapInfo: CGImageAlphaInfo.premultipliedLast.rawValue) else {
        print(path, "CTX_FAIL")
        return
    }
    ctx.draw(img, in: CGRect(x: 0, y: 0, width: width, height: height))
    var visible = 0
    var sumR = 0, sumG = 0, sumB = 0
    var minA = 255, maxA = 0
    var top: [String:Int] = [:]
    for i in stride(from: 0, to: data.count, by: 4) {
        let r = Int(data[i])
        let g = Int(data[i+1])
        let b = Int(data[i+2])
        let a = Int(data[i+3])
        minA = min(minA, a)
        maxA = max(maxA, a)
        if a > 0 {
            visible += 1
            sumR += r
            sumG += g
            sumB += b
            let key = "\(r),\(g),\(b),\(a)"
            top[key, default: 0] += 1
        }
    }
    let avg = visible > 0 ? "avgRGB=(\(sumR/visible),\(sumG/visible),\(sumB/visible))" : "avgRGB=NA"
    let common = top.sorted { $0.value > $1.value }.prefix(5).map { "\($0.key):\($0.value)" }.joined(separator: " | ")
    print(path)
    print("size=\(width)x\(height) visible=\(visible) alphaRange=\(minA)-\(maxA) \(avg)")
    print("top=\(common)")
}

